import React, { useState, useEffect } from "react";

const FIELDS = [
  "SUMMARY",
  "EDUCATION",
  "COMPETENCIES",
  "EXPERIENCE",
  "PROJECTS",
  "CERTS"
];

const cardStyle = {
  background: "#23272f",
  borderRadius: 18,
  padding: 32,
  boxShadow: "0 8px 36px rgba(0,0,0,0.4), 0 1.5px 7px #0008",
  maxWidth: 540,
  margin: "36px auto",
  color: "#f6f8fa",
  position: "relative"
};
const labelStyle = {
  display: "inline-block",
  fontWeight: 600,
  marginRight: 8,
  letterSpacing: 0.5,
  color:"#a7afd3"
};
const inputStyle = {
  background: "#232733",
  border: "1px solid #363951",
  color: "#d7e0f3",
  borderRadius: 8,
  padding: "8px 10px",
  fontSize: 16,
  outline: "none",
  width:"70%",
  marginBottom: 0,
};
const textareaStyle = {
  background: "#181a20",
  border: "1.5px solid #393f60",
  color: "#e0e6ec",
  borderRadius: 10,
  width: "100%",
  fontSize: 15,
  padding: 14,
  outline: "none",
  transition: "border 0.2s, box-shadow 0.2s",
  boxShadow: "0 1.5px 10px #0007",
  resize: "vertical",
  fontFamily: "Fira Mono, Menlo, monospace",
  marginTop: 6
};
const textareaFocusStyle = {
  border: "1.5px solid #406aff",
  boxShadow: "0 0 10px #406aff44"
};
const buttonStyle = {
  background: "linear-gradient(90deg, #375ffe, #472abd 84%)",
  color: "#fff",
  border: "none",
  borderRadius: 8,
  padding: "12px 28px",
  fontSize: 17,
  fontWeight: 700,
  cursor: "pointer",
  marginTop: 12,
  transition: "transform .1s, box-shadow .2s",
  boxShadow: "0 2.5px 20px #375ffe33, 0 1.5px 6px #37379934"
};
const buttonHoverStyle = {
  transform: "scale(1.05)",
  boxShadow: "0 4px 28px #375ffe55, 0 2px 8px #2227"
};
const spinnerStyle = {
  display: "inline-block",
  marginLeft: 14,
  width: 22,
  height: 22,
  border: "3px solid #444b",
  borderTop: "3px solid #fff",
  borderRadius: "50%",
  animation: "spin 0.85s linear infinite"
};
// Spinner animation (injecting global style)
if (typeof window !== "undefined" && !document.getElementById("spinstyle")) {
  const style = document.createElement("style");
  style.id = "spinstyle";
  style.innerHTML = `@keyframes spin{0%{transform:rotate(0deg);}100%{transform:rotate(360deg);}}`;
  document.head.appendChild(style);
}

export default function App() {
  const [text, setText] = useState("");
  const [loading, setLoading] = useState(false);
  const [backendUrl, setBackendUrl] = useState("http://localhost:4000");
  const [buttonHover, setButtonHover] = useState(false);
  const [focus, setFocus] = useState(false);
  const [showFixedInfo, setShowFixedInfo] = useState(false);
  const [fixedFields, setFixedFields] = useState(null);
  const [uploading, setUploading] = useState(false);
  const [uploadedFileName, setUploadedFileName] = useState(null);
  const format = "pdf"; // Only PDF is supported

  // Load fixed fields info on mount and when backend URL changes
  useEffect(() => {
    loadFixedFields();
  }, [backendUrl]);

  function loadFixedFields() {
    // First check if server is healthy
    fetch(`${backendUrl}/api/health`)
      .then(async res => {
        if (!res.ok) {
          console.warn(`Server health check failed: ${res.status}`);
          setFixedFields(null);
          return;
        }
        // Server is healthy, now load fixed fields
        return fetch(`${backendUrl}/api/fixed-fields`);
      })
      .then(async res => {
        if (!res) return null;
        
        // Check if response is JSON
        const contentType = res.headers.get("content-type");
        if (!contentType || !contentType.includes("application/json")) {
          const text = await res.text();
          console.error("Non-JSON response from fixed-fields:", text.substring(0, 200));
          console.warn("Backend server may not be running or URL is incorrect");
          setFixedFields(null);
          return null;
        }
        return res.json();
      })
      .then(data => {
        if (data) {
          setFixedFields(data);
          if (data.source === "uploaded") {
            setUploadedFileName("Uploaded Resume");
          } else {
            setUploadedFileName(null);
          }
        }
      })
      .catch(err => {
        console.error("Error loading fixed fields:", err);
        console.warn(`Make sure the backend server is running at ${backendUrl}`);
        setFixedFields(null);
      });
  }

  async function handleFileUpload(e) {
    const file = e.target.files[0];
    if (!file) return;

    if (file.type !== "application/pdf") {
      alert("Please upload a PDF file");
      return;
    }

    setUploading(true);
    const formData = new FormData();
    formData.append("resume", file);

    try {
      const response = await fetch(`${backendUrl}/api/upload-resume`, {
        method: "POST",
        body: formData
        // Don't set Content-Type header - browser will set it with boundary for FormData
      });

      // Check response status first
      if (!response.ok) {
        // Try to get error message from JSON
        let errorMsg = `Server error: ${response.status} ${response.statusText}`;
        try {
          const contentType = response.headers.get("content-type");
          if (contentType && contentType.includes("application/json")) {
            const errorData = await response.json();
            errorMsg = errorData.error || errorMsg;
          } else {
            const text = await response.text();
            console.error("Non-JSON error response:", text.substring(0, 500));
            errorMsg = `Server returned non-JSON error. Status: ${response.status}. Check console for details.`;
          }
        } catch (e) {
          console.error("Error parsing error response:", e);
        }
        alert(errorMsg);
        setUploading(false);
        return;
      }

      // Check if response is JSON
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        const text = await response.text();
        console.error("Non-JSON response:", text.substring(0, 500));
        alert(`Server error: Received non-JSON response. Is the backend server running at ${backendUrl}? Response: ${text.substring(0, 100)}`);
        setUploading(false);
        return;
      }

      const result = await response.json();

      // Response is already ok at this point (checked above)

      setUploadedFileName(file.name);
      const message = result.note 
        ? `${result.message}\n\n${result.note}\n\nExtracted ${result.extractedFields?.length || 0} fields.`
        : result.message || "Resume uploaded successfully! Fixed fields have been extracted.";
      alert(message);
      loadFixedFields(); // Reload fixed fields to show extracted data
    } catch (err) {
      console.error("Upload error:", err);
      alert("Network error: " + err.message + ". Make sure the backend server is running at " + backendUrl);
    } finally {
      setUploading(false);
    }
  }

  async function handleClearUploaded() {
    try {
      const response = await fetch(`${backendUrl}/api/clear-uploaded-resume`, {
        method: "POST",
        headers: { "Content-Type": "application/json" }
      });

      // Check if response is JSON
      const contentType = response.headers.get("content-type");
      if (!contentType || !contentType.includes("application/json")) {
        const text = await response.text();
        console.error("Non-JSON response:", text.substring(0, 200));
        alert(`Server error: Received non-JSON response. Is the backend server running at ${backendUrl}?`);
        return;
      }

      const result = await response.json();

      if (!response.ok) {
        alert("Error: " + (result.error || "Failed to clear uploaded resume"));
        return;
      }

      setUploadedFileName(null);
      loadFixedFields(); // Reload to show base resume
      alert("Using base resume data now");
    } catch (err) {
      console.error("Clear error:", err);
      alert("Network error: " + err.message + ". Make sure the backend server is running at " + backendUrl);
    }
  }

  async function handleGenerateAll(e) {
    e.preventDefault();
    setLoading(true);
    try {
      // Step 1. Ask backend AI to generate all fields from job desc
      const aiResponse = await fetch(`${backendUrl}/api/generate`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          description: text
        })
      });

      // Try to parse as JSON, handle errors gracefully
      let aiFields;
      try {
        const contentType = aiResponse.headers.get("content-type");
        if (contentType && contentType.includes("application/json")) {
          aiFields = await aiResponse.json();
        } else {
          // Not JSON, read as text to see what we got
          const text = await aiResponse.text();
          console.error("Non-JSON response from generate:", text.substring(0, 500));
          alert(`Server error: Received non-JSON response. Status: ${aiResponse.status}. Is the backend server running at ${backendUrl}?`);
          setLoading(false);
          return;
        }
      } catch (parseErr) {
        console.error("Error parsing JSON response:", parseErr);
        alert(`Error parsing server response. Make sure the backend server is running at ${backendUrl}`);
        setLoading(false);
        return;
      }

      if (!aiResponse.ok || !aiFields || !aiFields["summary"]) {
        alert('Error: ' + (aiFields?.error || 'No content generated!'));
        setLoading(false);
        return;
      }

      // Step 2. Inject all fields into the template and get PDF
      // Prepare replacements object: capitalize keys for the backend template
      const replacements = {};
      for (const f of FIELDS) {
        if (aiFields[f.toLowerCase()]) {
          replacements[f] = aiFields[f.toLowerCase()];
        }
      }

      const response = await fetch(`${backendUrl}/api/inject`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ replacements, format }),
      });

      // Check if response is JSON (for errors) or PDF (for success)
      const contentType = response.headers.get("content-type");
      if (!response.ok) {
        if (contentType && contentType.includes("application/json")) {
          const err = await response.json();
          alert("Error: " + (err.error || JSON.stringify(err)));
        } else {
          const text = await response.text();
          console.error("Non-JSON error response:", text.substring(0, 200));
          alert(`Server error: ${response.status} ${response.statusText}. Is the backend server running at ${backendUrl}?`);
        }
        setLoading(false);
        return;
      }

      // Check if we got a PDF
      if (!contentType || !contentType.includes("application/pdf")) {
        const text = await response.text();
        console.error("Expected PDF but got:", contentType, text.substring(0, 200));
        alert("Error: Server did not return a PDF file. Check backend logs.");
        setLoading(false);
        return;
      }

      // Handle PDF download
      const blob = await response.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = "resume.pdf";
      a.click();
      URL.revokeObjectURL(url);

    } catch (err) {
      alert("Network error: " + err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ background:"#171821", minHeight:"100vh", width:"100vw", padding:0, margin:0 }}>
      <div style={{ textAlign: "center", paddingTop: 32, paddingBottom: 10 }}>
        <h2 style={{ color:"#8ab7ff", fontWeight:900, letterSpacing:"-1px", fontSize:30, margin:0, textShadow: "0px 4px 14px #283bff44,0 1px 0 #282e82" }}>Auto Resume Builder</h2>
        <div style={{color: "#acb3d1", fontWeight: 400, marginTop: 3, fontSize: 19, letterSpacing:"-.03em",}}>One-Click AI Resumes from Any Job Ad</div>
      </div>
      <div style={cardStyle}>
        <div style={{ marginBottom: 20 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
            <p style={{ color: "#dde4ff", fontSize: 14, marginTop: 0, marginBottom: 0, flex: 1 }}>
              <b>Step 1:</b> Upload your resume PDF (optional) or use base resume
            </p>
          </div>
          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <label
              style={{
                background: "#2d3748",
                color: "#fff",
                border: "1px solid #4caf50",
                borderRadius: 6,
                padding: "8px 16px",
                fontSize: 13,
                cursor: uploading ? "not-allowed" : "pointer",
                fontWeight: 600,
                opacity: uploading ? 0.6 : 1,
                display: "inline-block"
              }}
            >
              {uploading ? "Uploading..." : "📄 Upload Resume PDF"}
              <input
                type="file"
                accept=".pdf"
                onChange={handleFileUpload}
                disabled={uploading}
                style={{ display: "none" }}
              />
            </label>
            {uploadedFileName && (
              <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                <span style={{ color: "#81c784", fontSize: 12 }}>
                  ✓ {uploadedFileName}
                </span>
                <button
                  type="button"
                  onClick={handleClearUploaded}
                  style={{
                    background: "#d32f2f",
                    color: "#fff",
                    border: "none",
                    borderRadius: 4,
                    padding: "4px 8px",
                    fontSize: 11,
                    cursor: "pointer",
                    fontWeight: 600
                  }}
                >
                  Clear
                </button>
              </div>
            )}
          </div>
        </div>

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <p style={{ color: "#dde4ff", fontSize: 15, marginTop: 0, marginBottom: 0, flex: 1 }}>
            <b>Step 2:</b> Paste the <b>job description</b> below. AI will tailor <b style={{color: "#4fc3f7"}}>Summary, Competencies, Experience Content, Projects</b> while keeping your <b style={{color: "#81c784"}}>Name, Contact, Education, Certificates, Patents</b> fixed.
          </p>
          <button
            type="button"
            onClick={() => setShowFixedInfo(!showFixedInfo)}
            style={{
              background: showFixedInfo ? "#4caf50" : "#2d3748",
              color: "#fff",
              border: "1px solid #4caf50",
              borderRadius: 6,
              padding: "6px 12px",
              fontSize: 12,
              cursor: "pointer",
              marginLeft: 12,
              fontWeight: 600
            }}
          >
            {showFixedInfo ? "Hide" : "Show"} Fixed Info
          </button>
        </div>

        {showFixedInfo && fixedFields && (
          <div style={{
            background: "#1a1f2e",
            border: "1px solid #4caf50",
            borderRadius: 8,
            padding: 12,
            marginBottom: 16,
            fontSize: 13
          }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
              <div style={{ color: "#81c784", fontWeight: 700 }}>🔒 Fixed Fields (Won't Change):</div>
              {fixedFields.source && (
                <div style={{ 
                  color: fixedFields.source === "uploaded" ? "#81c784" : "#90a4ae", 
                  fontSize: 11,
                  fontStyle: "italic"
                }}>
                  {fixedFields.source === "uploaded" ? "📄 From Uploaded PDF" : "📋 From Base Resume"}
                </div>
              )}
            </div>
            <div style={{ color: "#b0bec5", lineHeight: 1.6 }}>
              <div><strong>Name:</strong> {fixedFields.name}</div>
              <div><strong>Contact:</strong> {fixedFields.email} | {fixedFields.phone}</div>
              <div><strong>LinkedIn:</strong> {fixedFields.linkedin || "Not provided"}</div>
              <div><strong>Portfolio:</strong> {fixedFields.portfolio || "Not provided"}</div>
              <div style={{ marginTop: 6 }}><strong>Education:</strong> {fixedFields.education ? fixedFields.education.split('\n')[0] : "Not provided"}</div>
              <div><strong>Certificates/Patents:</strong> {fixedFields.certs ? (fixedFields.certs.length > 100 ? fixedFields.certs.substring(0, 100) + "..." : fixedFields.certs) : "Not provided"}</div>
              {fixedFields.experienceTitles && fixedFields.experienceTitles.length > 0 && (
                <div style={{ marginTop: 6 }}>
                  <strong>Experience Titles:</strong>
                  {fixedFields.experienceTitles.map((title, i) => (
                    <div key={i} style={{ marginLeft: 12, fontSize: 12, color: "#90a4ae" }}>• {title}</div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}

        <form onSubmit={handleGenerateAll} autoComplete="off">
          <div style={{marginBottom:14}}>
            <label style={labelStyle}>Backend URL:</label>
            <input
              type="text"
              value={backendUrl}
              onChange={e => setBackendUrl(e.target.value)}
              style={inputStyle}
            />
          </div>
          <textarea
            value={text}
            onChange={e => setText(e.target.value)}
            rows={12}
            style={{
              ...textareaStyle,
              ...(focus ? textareaFocusStyle : {})
            }}
            placeholder="Paste the job description here."
            onFocus={() => setFocus(true)}
            onBlur={() => setFocus(false)}
            required
          />
          <div style={{ marginTop: 18, textAlign: "center" }}>
            <button
              type="submit"
              disabled={loading || !text.trim()}
              style={buttonHover ? {...buttonStyle, ...buttonHoverStyle} : buttonStyle}
              onMouseEnter={() => setButtonHover(true)}
              onMouseLeave={() => setButtonHover(false)}
            >
              {loading ? (
                <span>Generating<Spinner/></span>
              ) : (
                <span>Generate Resume PDF</span>
              )}
            </button>
          </div>
        </form>
      </div>
      <div style={{ textAlign: "center", marginTop: 66, color:'#39547988',fontSize:16 }}>
        Built with AI Resume Magic
      </div>
    </div>
  );
}

function Spinner() {
  return <span style={spinnerStyle}></span>;
}
